```kotlin
fun solve(s: String): String {
    val result = mutableListOf<Char>()
    for (c in s) {
        when (c) {
            in 'a'..'z' -> result.add(c)
            '*' -> {
                if (result.isNotEmpty()) {
                    result.removeLast()
                }
            }
            '#' -> {
                result = result + result
            }
            '%' -> {
                result = result.reversed().toMutableList()
            }
        }
    }
    return result.joinToString("")
}
```

